// src/SiparisOlustur.js
import React, { useEffect, useMemo, useRef, useState } from "react";
import { Download, Link as LinkIcon, ListChecks, IdCard, FileSpreadsheet, UploadCloud } from "lucide-react";
import * as XLSX from "xlsx";
import "./SiparisOlustur.css";
import supabase from "../supabaseClient";

/**
 * HANGİ TABLODAN VERİ ÇEKİLECEK?
 * Kendi tablo adınıza göre güncelleyin.
 */
const DATA_TABLE = "Siparisler";

/**
 * TABLODA KULLANILACAK GÜNCEL BAŞLIKLAR
 */
const HEADERS = [
    "Vkn",
    "Proje",
    "Sipariş Tarihi",
    "Yükleme Tarihi",
    "Teslim Tarihi",
    "Müşteri Sipariş No",
    "Müşteri Referans No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firması Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
    "İrsaliye No",
    "İrsaliye Miktarı",
    "Ürün",
    "Kap Adet",
    "Ambalaj  Tipi",
    "Brüt KG",
    "M3",
    "Desi",
];

/**
 * Kaynaktan gelen kolon -> Tablodaki başlık eşlemesi
 * (Gerekirse bu map'i düzenleyin)
 */
const FIELD_MAP = {
    vkn: "Vkn",
    proje_id: "Proje", // tabloda proje adı gösterilecek (id değil)
    Musteri_Siparis_No: "Müşteri Sipariş No",
    Alici_Firma_Cari_Unvani: "Alıcı Firma Cari Adı",
    Urun: "Ürün",
    Kap_Adet: "Kap Adet",
    Ambalaj_Tipi: "Ambalaj  Tipi",
    Brut_KG: "Brüt KG",
    Yukleme_Firma_Adres_Adi: "Yükleme Firması Adı",
};

/**
 * Export’ta çıkacak ve import’ta zorunlu tutulacak 7 başlık
 */
const REQUIRED_EXPORT_HEADERS = [
    "Sipariş Tarihi",
    "Müşteri Sipariş No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firması Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
];

const emptyRow = () => HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});
const sortTr = (a, b) => String(a).localeCompare(String(b), "tr", { sensitivity: "base" });
const normalize = (s) => String(s || "").replace(/\s+/g, " ").trim();

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [rows, setRows] = useState([]); // Excel veya projeden doldurulur
    const [dragActive, setDragActive] = useState(false);
    const [error, setError] = useState("");
    const [lastFile, setLastFile] = useState(null);
    const fileInputRef = useRef(null);

    // Projeler
    const [projects, setProjects] = useState([]); // {id, name}
    const [projectsLoading, setProjectsLoading] = useState(false);
    const [projectsError, setProjectsError] = useState("");

    // Projeye göre çekilen veriler için durum
    const [dataLoading, setDataLoading] = useState(false);

    const columns = useMemo(() => HEADERS, []);

    // --- Projeleri Supabase'ten yükle (id + Proje_Adi) ---
    useEffect(() => {
        const fetchProjects = async () => {
            setProjectsLoading(true);
            setProjectsError("");
            try {
                const { data, error } = await supabase
                    .from("Projeler")
                    .select("id, Proje_Adi");

                if (error) throw error;

                const list = (Array.isArray(data) ? data : [])
                    .map((x) => ({
                        id: x?.id,
                        name: (x?.Proje_Adi ?? "").trim(),
                    }))
                    .filter((x) => x.id && x.name.length > 0)
                    .sort((a, b) => sortTr(a.name, b.name));

                setProjects(list);
            } catch (e) {
                setProjectsError(e.message || "Projeler alınırken hata oluştu.");
                setProjects([]);
            } finally {
                setProjectsLoading(false);
            }
        };

        fetchProjects();
    }, []);

    // --- Proje seçimi ZORUNLU: Proje değiştiğinde ilgili satırları tablonuza göre çek ---
    useEffect(() => {
        const loadDataForProject = async () => {
            setError("");
            setRows([]);
            setLastFile(null);

            if (!projeAdi) return; // seçilmeden veri çekme

            const selected = projects.find((p) => p.name === projeAdi);
            if (!selected) {
                setError("Seçilen proje bulunamadı.");
                return;
            }

            setDataLoading(true);
            try {
                // Kaynaktan ihtiyacımız olan kolonları alıyoruz
                const selectCols = [
                    "vkn",
                    "proje_id",
                    "Musteri_Siparis_No",
                    "Alici_Firma_Cari_Unvani",
                    "Urun",
                    "Kap_Adet",
                    "Ambalaj_Tipi",
                    "Brut_KG",
                    "Yukleme_Firma_Adres_Adi",
                ].join(", ");

                // proje_id ile bağlı kayıtları çek
                const { data, error } = await supabase
                    .from(DATA_TABLE)
                    .select(selectCols)
                    .eq("proje_id", selected.id);

                if (error) throw error;

                const incoming = Array.isArray(data) ? data : [];

                // Gelen kayıtları tablo HEADERS formatına dönüştür
                const mappedRows = incoming.map((rec) => {
                    const base = emptyRow();

                    Object.entries(FIELD_MAP).forEach(([src, dest]) => {
                        if (src === "proje_id") {
                            // tabloda "Proje" hücresine ad yazılacak
                            base[dest] = projeAdi;
                        } else {
                            base[dest] = normalize(rec?.[src]);
                        }
                    });

                    return base;
                });

                setRows(mappedRows);
            } catch (e) {
                setError(e.message || "Proje verileri alınırken hata oluştu.");
                setRows([]);
            } finally {
                setDataLoading(false);
            }
        };

        loadDataForProject();
    }, [projeAdi, projects]);

    // --- Şablon indir / dışa aktar ---
    const handleTemplateDownload = () => {
        const cols = REQUIRED_EXPORT_HEADERS;
        const wsData = [cols, ...[emptyRow()].map((r) => cols.map((c) => r[c] ?? ""))];
        const ws = XLSX.utils.aoa_to_sheet(wsData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, `Siparis_Sablon_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleExportExcel = () => {
        if (!projeAdi) {
            setError("Dışa aktarmadan önce lütfen bir proje seçin.");
            return;
        }
        const data = rows.map((r) => {
            const obj = {};
            REQUIRED_EXPORT_HEADERS.forEach((h) => (obj[h] = r[h] ?? ""));
            return obj;
        });
        const ws = XLSX.utils.json_to_sheet(data, { header: REQUIRED_EXPORT_HEADERS });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Siparisler");
        XLSX.writeFile(wb, `Siparisler_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    // --- Demo aksiyonlar (stub) ---
    const handleEslesmeYap = () => {
        if (!projeAdi) {
            setError("Eşleşme yapmadan önce lütfen bir proje seçin.");
            return;
        }
        alert("Eşleşme işlemi tetiklendi (API bağlayın).");
    };

    const handleEslesmeIdGetir = () => {
        if (!projeAdi) {
            setError("Eşleşme ID’lerini getirmeden önce lütfen bir proje seçin.");
            return;
        }
        const fakeId = Math.random().toString(36).slice(2, 10).toUpperCase();
        alert(`Eşleşme ID'si: ${fakeId}`);
    };

    // --- Excel içe aktarım ---
    const isExcelFile = (file) =>
        /\.(xlsx|xlsm|xls)$/i.test(file.name) ||
        [
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-excel",
        ].includes(file.type);

    const parseExcel = async (file) => {
        setError("");
        try {
            if (!projeAdi) throw new Error("Excel yüklemeden önce lütfen bir proje seçin.");
            if (!isExcelFile(file)) throw new Error("Lütfen .xlsx / .xls dosyası yükleyin.");
            const data = await file.arrayBuffer();
            const wb = XLSX.read(data, { type: "array" });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });
            if (!aoa || aoa.length === 0) throw new Error("Boş sayfa görünüyor.");

            const [rawHeaders, ...body] = aoa;

            // Header eşleme
            const headerIndexMap = {};
            HEADERS.forEach((h) => {
                const idx = rawHeaders.findIndex((x) => normalize(x) === normalize(h));
                headerIndexMap[h] = idx; // -1 olabilir
            });

            // Zorunlu başlıklar
            const required = REQUIRED_EXPORT_HEADERS;
            const missing = required.filter((h) => headerIndexMap[h] === -1);
            if (missing.length) throw new Error(`Eksik başlık: ${missing.join(", ")}. Lütfen şablonu kullanın.`);

            const parsedRows = body
                .filter((row) => row.some((cell) => normalize(cell) !== ""))
                .map((row) => {
                    const obj = {};
                    HEADERS.forEach((h) => {
                        const idx = headerIndexMap[h];
                        obj[h] = idx >= 0 ? normalize(row[idx]) : "";
                    });
                    return obj;
                })
                // Proje sütununu seçili proje ile doldur
                .map((r) => ({ ...r, ["Proje"]: projeAdi || "" }));

            setRows(parsedRows);
            setLastFile(file);
        } catch (e) {
            setRows([]);
            setError(e.message || "Excel okunamadı.");
        }
    };

    // Drag & drop handlers
    const onDrop = (e) => {
        e.preventDefault();
        setDragActive(false);
        const f = e.dataTransfer.files?.[0];
        if (f) parseExcel(f);
    };
    const onDragOver = (e) => {
        e.preventDefault();
        setDragActive(true);
    };
    const onDragLeave = () => setDragActive(false);
    const pickFile = () => fileInputRef.current?.click();
    const onFileChange = (e) => {
        const f = e.target.files?.[0];
        if (f) parseExcel(f);
        e.target.value = "";
    };

    return (
        <div className="so-page">
            <div className="so-header">
                <div>
                    <h1 className="so-title">Sipariş Oluştur</h1>
                    <div className="so-subtitle">SiparisOlustur.js</div>
                </div>
            </div>

            {/* ÜSTTE AYRIK İKİ PANEL */}
            <div className="so-grid so-grid--two">
                {/* Sol panel */}
                <div className="so-card so-equal">
                    <label className="so-label">Proje Adı <span style={{ color: "#e11d48" }}>*</span></label>
                    <select
                        className="so-input"
                        value={projeAdi}
                        onChange={(e) => setProjeAdi(e.target.value)}
                        disabled={projectsLoading}
                    >
                        <option value="">Seçiniz</option>
                        {projectsLoading && <option>Yükleniyor...</option>}
                        {!projectsLoading && projectsError && <option disabled>Hata: {projectsError}</option>}
                        {!projectsLoading &&
                            !projectsError &&
                            projects.map((p) => (
                                <option key={p.id} value={p.name}>
                                    {p.name}
                                </option>
                            ))}
                    </select>
                    <p className="so-help">
                        Proje seçmek zorunludur. Seçtiğiniz projeye ait kayıtlar otomatik tabloya getirilir.
                        {projectsError && (
                            <>
                                <br />
                                <span className="so-error">
                                    Projeler alınamadı. Supabase bağlantısını ve RLS kurallarını kontrol edin.
                                </span>
                            </>
                        )}
                    </p>
                </div>

                {/* Sağ panel */}
                <div className="so-card so-equal">
                    <div className="so-actions">
                        <button className="so-btn so-btn-primary" onClick={handleTemplateDownload}>
                            <Download size={18} /> Şablonu İndir
                        </button>
                        <button className="so-btn" onClick={handleEslesmeYap} disabled={!projeAdi}>
                            <LinkIcon size={18} /> Eşleşme Yap
                        </button>
                        <button className="so-btn" onClick={handleEslesmeIdGetir} disabled={!projeAdi}>
                            <IdCard size={18} /> Eşleşme ID’lerini Getir
                        </button>
                        <button className="so-btn" onClick={handleExportExcel} disabled={!rows.length || !projeAdi}>
                            <FileSpreadsheet size={18} /> Dışarı Excel Aktarma
                        </button>
                    </div>
                </div>
            </div>

            {/* ALT PANEL */}
            <div className="so-table-card">
                <div className="so-table-header">
                    <ListChecks size={18} /> <span>Şablon</span>
                    <span className="so-table-sub">(İçerik Excel ile yüklenir veya proje seçimiyle otomatik gelir)</span>
                </div>

                <div className="so-table-wrap">
                    <table className="so-table">
                        <thead>
                            <tr>
                                <th className="so-index">#</th>
                                {columns.map((c) => (
                                    <th key={c}>{c}</th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.length === 0 ? (
                                <tr className="so-drop-row">
                                    <td className="so-index" colSpan={columns.length + 1}>
                                        <div
                                            className={`so-drop-in-table ${dragActive ? "active" : ""}`}
                                            onDrop={onDrop}
                                            onDragOver={onDragOver}
                                            onDragLeave={onDragLeave}
                                            onDragEnd={onDragLeave}
                                            onDragExit={onDragLeave}
                                            onClick={pickFile}
                                            role="button"
                                            aria-label="Excel sürükleyip bırak veya tıklayıp seç"
                                            tabIndex={0}
                                        >
                                            <UploadCloud size={30} />
                                            <div className="so-drop-title">
                                                {dataLoading ? "Proje verileri getiriliyor..." : "Excel’i buraya sürükleyip bırakın"}
                                            </div>
                                            <div className="so-drop-sub">
                                                ya da <b>tıklayın</b> (.xlsx / .xls)
                                            </div>
                                            <input
                                                ref={fileInputRef}
                                                type="file"
                                                accept=".xlsx,.xls,.xlsm"
                                                onChange={onFileChange}
                                                hidden
                                                disabled={!projeAdi}
                                            />
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                rows.map((row, rowIdx) => (
                                    <tr key={rowIdx}>
                                        <td className="so-index">{rowIdx + 1}</td>
                                        {columns.map((col) => (
                                            <td key={`${rowIdx}-${col}`}>
                                                <div className="so-cell-text">{row[col]}</div>
                                            </td>
                                        ))}
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                <div className="so-footnote">
                    İpucu: “Şablonu İndir” ile başlıkları hazır Excel elde edip, doldurduktan sonra buraya yükleyebilirsiniz.
                </div>

                {error && <p className="so-error">{error}</p>}
                {lastFile && (
                    <p className="so-help">
                        Yüklü: <b>{lastFile.name}</b>
                    </p>
                )}
            </div>
        </div>
    );
}
